#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a, b;
    int win1 = 0, win2 = 0, draw = 0;
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &a, &b);
        if (a > b) win1++;
        else if (a < b) win2++;
        else draw++;
    }
    printf("%d %d %d\n", win1, win2, draw);
    return 0;
}

