code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int a, b;
        int win1 = 0, win2 = 0, draw = 0;
        for (int i = 0; i < n; i++) {
            a = scanner.nextInt();
            b = scanner.nextInt();
            if (a > b) win1++;
            else if (a < b) win2++;
            else draw++;
        }
        System.out.println(win1 + " " + win2 + " " + draw);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a, b;
let win1 = 0, win2 = 0, draw = 0;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        [a, b] = line.split(' ').map(num => parseInt(num));
        if (a > b) win1++;
        else if (a < b) win2++;
        else draw++;
        if (i === n) {
            console.log(win1 + ' ' + win2 + ' ' + draw);
            readline.close();
        }
    }
    i++;
});

